import jibo = require('jibo');
import TimeUtil from '../../utils/TimeUtil';

export default class RecipeMenuItem extends jibo.rendering.gui.components.Button {

  static createFromConfig (config: any): RecipeMenuItem {
    let btn: RecipeMenuItem = new RecipeMenuItem();
    btn.assignConfig(config);
    return btn;
  }

  public static TYPE: string = 'RecipeMenuItem';

  constructor () {
    super();
  }

  public setupDisplay (assets: any): void {
    super.setupDisplay(assets);

    let {
      title_txt,
      reviews_txt,
      totalTime_txt,
      serving_txt,
      ratingFull,
      recipeImage
    } = (<any>this.display.getChildAt(0)).children[0];

    let { data, index } = <any>this.assetDescriptors[0];
    let title = data.title.replace(/\s/g, '').toLowerCase();
    let labels = recipeImage._labels;
    for (let i = 0, l = labels.length; i < l; i++) {
      if (labels[i].label === title) {
        recipeImage.gotoAndStop(i);
        break;
      }
    }

    title_txt.text = data.title;
    this.setStyleProp(title_txt, 'wordWrap', true);

    // this.setStyleProp(title_txt, 'lineHeight', 120);

    let ratingAverage = Math.round(data.ratingAverage);
    ratingFull.children.forEach((child, i) => child.gotoAndStop(i + 1 < ratingAverage ? 0 : 1));
    let displayTime = TimeUtil.minutesToTime(data.readyInMinutes);
    totalTime_txt.text = `${displayTime.h} h ${displayTime.m} m`;
    serving_txt.text = `${data.servings} Servings`;

    reviews_txt.text = `${data.reviewCount} Reviews`;
    this.setStyleProp(reviews_txt, 'textAlign', 'center');
    reviews_txt.x = this.alignClips(ratingFull, reviews_txt);
  }

  private setStyleProp (obj: PIXI.Text, prop: string, value: any) {
    obj.style[prop] = value;
    // let the Text object know the text style has changed.
    obj.style = obj.style;
  }

  private alignClips (referenceClip, centeringClip, type: string = '') {
    // SD: Case Reference clip regX/regY = 0, centeringClip regX/regY = centered;
    return (referenceClip.x + (centeringClip.width / 2)) + (referenceClip.width / 2) - (centeringClip.width / 2)
  }

}
